  def withDefaultChain(region: Region = Region.US_EAST_1): CredentialManager = {
    new CredentialManager(DefaultChain, region)
  }

  def withEnvironmentCredentials(region: Region = Region.US_EAST_1): CredentialManager = {
    val accessKey = sys.env.getOrElse("AWS_ACCESS_KEY_ID",
      throw new IllegalStateException("AWS_ACCESS_KEY_ID environment variable not set"))
    val secretKey = sys.env.getOrElse("AWS_SECRET_ACCESS_KEY",
      throw new IllegalStateException("AWS_SECRET_ACCESS_KEY environment variable not set"))

    val sessionToken = sys.env.get("AWS_SESSION_TOKEN")

    val mode = sessionToken match {
      case Some(token) => SessionCredentials(accessKey, secretKey, token)
      case None => StaticCredentials(accessKey, secretKey)
    }

    new CredentialManager(mode, region)
  }
}

