object AwsServiceApp extends App {

  // Example 1: Using default credential chain (recommended for production)
  val manager = AwsServiceManager.withDefaultCredentials(Region.US_EAST_1)

  try {
    // Validate credentials
    manager.validateConnection() match {
      case AwsSuccess(msg) => println(s"Connection validated: $msg")
      case AwsFailure(err, _) => println(s"Connection failed: $err")
    }

    // Use S3 service
    val s3 = manager.getS3Service

    s3.listBuckets() match {
      case AwsSuccess(buckets) =>
        println(s"Found ${buckets.size} buckets:")
        buckets.foreach(b => println(s"  - $b"))
      case AwsFailure(err, _) =>
        println(s"Failed to list buckets: $err")
    }

    // Use STS service
    val sts = manager.getStsService

    sts.getCallerIdentity() match {
      case AwsSuccess(identity) =>
        println(s"Account: ${identity.account}")
        println(s"ARN: ${identity.arn}")
        println(s"User ID: ${identity.userId}")
      case AwsFailure(err, _) =>
        println(s"Failed to get identity: $err")
    }

  } finally {
    manager.close()
  }
}